<?php
/**
 * EPOS Dashboard Navigation Patch Fixed
 *
 * Clean WPCode-safe version.
 */

if (!defined('ABSPATH')) {
    exit;
}

if (!function_exists('epos_dashboard_navigation_patch_fixed_render')) {
    function epos_dashboard_navigation_patch_fixed_render() {
        $rest_nonce = wp_create_nonce('wp_rest');
        $rest_base  = esc_url_raw(rest_url('ep/v1/'));

        echo '<script>(function(){';
        echo 'var restBase=' . wp_json_encode($rest_base) . ';';
        echo 'var restNonce=' . wp_json_encode($rest_nonce) . ';';
        echo "function esc(text){return String(text==null?'':text).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\\\"/g,'&quot;').replace(/'/g,'&#039;');}";
        echo "async function getJson(endpoint){var response=await fetch(restBase+endpoint,{method:'GET',credentials:'same-origin',headers:{'Content-Type':'application/json','X-WP-Nonce':restNonce}});if(!response.ok)throw new Error('Request failed: '+response.status+' ('+endpoint+')');return response.json();}";
        echo "function items(result){return result&&result.data&&Array.isArray(result.data.items)?result.data.items:[];}";
        echo "function setActive(link){document.querySelectorAll('#epos-dashboard-prototype-exact-wrapper nav a').forEach(function(a){a.classList.remove('bg-zinc-100','dark:bg-zinc-900','border','border-zinc-200','dark:border-zinc-800');var bar=a.querySelector('div.absolute.left-0');if(bar)bar.remove();});link.classList.add('bg-zinc-100','dark:bg-zinc-900','border','border-zinc-200','dark:border-zinc-800');if(!link.querySelector('div.absolute.left-0')){var bar=document.createElement('div');bar.className='absolute left-0 top-0 bottom-0 w-1 chrome-gold-bg-anim';link.prepend(bar);}}";
        echo "function panel(title,subtitle,tableHtml){return '<div class=\"mb-8 relative z-10\"><p class=\"chrome-gold-text uppercase tracking-widest text-xs font-bold mb-2 font-mono\">02 // MODULE</p><h1 class=\"text-3xl md:text-4xl font-black tracking-tighter text-zinc-900 dark:text-white transition-colors\">'+esc(title)+'</h1><p class=\"text-zinc-500 dark:text-zinc-400 mt-2\">'+esc(subtitle||'')+'</p></div><div class=\"bg-white/80 dark:bg-zinc-900/80 backdrop-blur-sm rounded-[1.5rem] border border-zinc-200 dark:border-zinc-800 shadow-xl flex flex-col overflow-hidden transition-colors duration-300\">'+tableHtml+'</div>'; }";
        echo "function table(columns,rows){var head='<tr class=\"bg-zinc-100/50 dark:bg-black/40 text-zinc-500 dark:text-zinc-500 text-[10px] uppercase font-bold border-b border-zinc-200 dark:border-zinc-800 transition-colors\">'+columns.map(function(c){return '<th class=\"p-5\">'+esc(c)+'</th>';}).join('')+'</tr>';var body=rows.length?rows.join(''):'<tr><td class=\"p-5\" colspan=\"'+columns.length+'\">No records found.</td></tr>';return '<div class=\"p-0 overflow-x-auto\"><table class=\"w-full text-left border-collapse evo-table\"><thead>'+head+'</thead><tbody class=\"text-sm divide-y divide-zinc-200 dark:divide-zinc-800/50 transition-colors\">'+body+'</tbody></table></div>'; }";
        echo "async function renderModule(name,main,originalHtml){try{if(name==='dashboard'){main.innerHTML=originalHtml;return;}if(name==='crm'){var clients=items(await getJson('clients'));var rows=clients.slice(0,25).map(function(item){return '<tr><td class=\"p-5 font-bold text-zinc-900 dark:text-white\">'+esc(item.full_name||'N/A')+'</td><td class=\"p-5\">'+esc(item.email||'')+'</td><td class=\"p-5\">'+esc(item.phone||'')+'</td><td class=\"p-5\">'+esc(item.status||'')+'</td></tr>';});main.innerHTML=panel('CRM','Client records loaded from the backend.',table(['Name','Email','Phone','Status'],rows));return;}if(name==='pipelines'){var opportunities=items(await getJson('opportunities'));var rowsOpp=opportunities.slice(0,25).map(function(item){return '<tr><td class=\"p-5 font-bold text-zinc-900 dark:text-white\">'+esc(item.title||'Untitled')+'</td><td class=\"p-5\">'+esc(item.pipeline_stage||'')+'</td><td class=\"p-5\">'+esc(item.status||'')+'</td><td class=\"p-5\">$'+esc(item.estimated_value||'0.00')+'</td></tr>';});main.innerHTML=panel('Pipelines','Opportunity pipeline records.',table(['Opportunity','Stage','Status','Value'],rowsOpp));return;}if(name==='projects'){var projects=items(await getJson('projects'));var rowsProjects=projects.slice(0,25).map(function(item){return '<tr><td class=\"p-5 font-bold text-zinc-900 dark:text-white\">'+esc(item.title||'Untitled')+'</td><td class=\"p-5\">'+esc(item.address||'')+'</td><td class=\"p-5\">'+esc(item.status||'')+'</td><td class=\"p-5\">'+esc(item.start_date||'')+'</td></tr>';});main.innerHTML=panel('Projects','Project records loaded from the backend.',table(['Project','Address','Status','Start Date'],rowsProjects));return;}if(name==='estimators'){var estimators=items(await getJson('estimators'));var rowsEstimators=estimators.slice(0,25).map(function(item){return '<tr><td class=\"p-5 font-bold text-zinc-900 dark:text-white\">#'+esc(item.id||'')+'</td><td class=\"p-5\">'+esc(item.address||'')+'</td><td class=\"p-5\">'+esc(item.roof_type||'')+'</td><td class=\"p-5\">$'+esc(item.total_estimated_price||'0.00')+'</td></tr>';});main.innerHTML=panel('Estimators','Estimator records loaded from the backend.',table(['ID','Address','Roof Type','Total'],rowsEstimators));return;}if(name==='contracts'){var contracts=items(await getJson('contracts'));var rowsContracts=contracts.slice(0,25).map(function(item){return '<tr><td class=\"p-5 font-bold text-zinc-900 dark:text-white\">'+esc(item.contract_number||'N/A')+'</td><td class=\"p-5\">'+esc(item.client_name||'')+'</td><td class=\"p-5\">$'+esc(item.contract_amount||'0.00')+'</td><td class=\"p-5\">'+esc(item.status||'')+'</td></tr>';});main.innerHTML=panel('Contracts','Contract records loaded from the backend.',table(['Contract #','Client','Amount','Status'],rowsContracts));return;}if(name==='bundles'){main.innerHTML=panel('Bundles','Bundle module is reserved for the next backend phase.','<div class=\"p-6 text-zinc-500 dark:text-zinc-400\">No bundle backend endpoint is active in the current phase.</div>');}}catch(error){main.innerHTML='<div class=\"mb-8 relative z-10\"><h1 class=\"text-3xl md:text-4xl font-black tracking-tighter text-zinc-900 dark:text-white transition-colors\">Module Error</h1><p class=\"text-red-400 mt-4\">'+esc(error.message||'Unknown error')+'</p></div>';}}";
        echo "function boot(){var wrapper=document.getElementById('epos-dashboard-prototype-exact-wrapper');if(!wrapper)return false;var main=wrapper.querySelector('main');var nav=wrapper.querySelector('nav');if(!main||!nav)return false;if(wrapper.getAttribute('data-epos-nav-patch')==='1')return true;wrapper.setAttribute('data-epos-nav-patch','1');var originalHtml=main.innerHTML;var links=Array.prototype.slice.call(nav.querySelectorAll('a'));links.forEach(function(link){var label=(link.textContent||'').trim().toLowerCase();var map={'dashboard':'dashboard','crm':'crm','pipelines':'pipelines','projects':'projects','estimators':'estimators','contracts':'contracts','bundles':'bundles'};var view=map[label];if(!view)return;link.addEventListener('click',function(e){e.preventDefault();setActive(link);renderModule(view,main,originalHtml);});});return true;}";
        echo "if(!boot()){var tries=0;var timer=setInterval(function(){tries++;if(boot()||tries>40)clearInterval(timer);},250);}”; 
        echo '})();</script>';
    }
}

add_action('wp_footer', 'epos_dashboard_navigation_patch_fixed_render', 999);
